from abc import ABC, abstractmethod
from pathlib import PurePath
from typing import List


class UrlProtocol(ABC):
    @abstractmethod
    def integrate_path(self, url: str, path: PurePath) -> str:
        """Integrate the name of a pathlib.PurePath object to an url"""

    @abstractmethod
    def extract_path(self, url: str) -> PurePath:
        """Extract an absolute PurePath object to the url"""

    @classmethod
    def is_protocol_url(cls, url: str) -> bool:
        return cls.extract_scheme(url) == cls.get_scheme()

    @staticmethod
    @abstractmethod
    def get_scheme() -> str:
        pass

    @staticmethod
    def split(url: str) -> tuple:
        split = url.split("://")
        if len(split) == 2:
            return tuple(split)
        elif len(split) == 1:
            return "", split[0]
        else:
            raise RuntimeError("Invalid URL: '{}'".format(url))

    @classmethod
    def extract_scheme(cls, url: str) -> str:
        """Get the scheme of the url"""
        return cls.split(url)[0]

    @abstractmethod
    def request(self, url: str) -> List[str]:
        """List recursively the url of the objects in the directory located at 'url'"""

    @abstractmethod
    def exists(self, url: str) -> bool:
        """Indicate if the object pointed by the url exists"""

    @abstractmethod
    def list(self, url: str) -> list:
        """List the url of the objects in the directory located at 'url'"""

    @abstractmethod
    def pull(self, url: str) -> str:
        """This function pulls the file pointed by the url onto the local disk"""

    @abstractmethod
    def push(self, url: str) -> str:
        """Push the local file to the destination pointed by url.
        The local url is computed from the destination url, best used after 'Pull'
        """

    def commit(self, url: str):
        """Push and then delete the local cache"""
        self.push(url)
        self.delete_cache(url)

    @abstractmethod
    def receive(self, url: str, stream):
        """Write the content pointed by the url to the returned stream"""

    @abstractmethod
    def send(self, url: str, stream):
        """Send the content of the stream to the url location"""

    @abstractmethod
    def delete_cache(self, url: str) -> str:
        """Delete the temporary data generated during Pull"""

    @abstractmethod
    def remove(self, url: str):
        """Remove the file located at url"""

    @abstractmethod
    def open(self, url: str, mode: str):
        """Shall return a file object corresponding to the path

        allowed modes are: 'r', 'rb', 'w', 'wb'
        """
